var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 넌 여기 온 첫날에 봤던 그 교도관 끄나풀이잖아?","JPN":"って、あんたは初日に会った刑務官の手先じゃん。","ENG":"No, you're that officer's lackey I met on my first day here.","TWN":"不對，你是我被押到這裡的第一天遇到的那獄警的奸細？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"끄나풀이라뇨. 가이드입니다.","JPN":"手先って……ガイドですよ。","ENG":"Lackey? I am a guide, mind you.","TWN":"不是奸細，是小幫手。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그나저나, 엣지존에 수감된 죄수가 에이미 양이었습니까?","JPN":"それより、エッジゾーンに収容された囚人って、エイミーさんだったんですか？","ENG":"But I didn't know you were the prisoner held in the edge zone, Amy.","TWN":"話說被關進邊緣區域的囚犯竟然是艾米？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"이런 곳에 갇힐 정도로 위험한 사람처럼 보이진 않았는데요.","JPN":"こんなところに閉じ込められるほど危険な人には見えませんでしたけど。","ENG":"You didn't seem like someone so dangerous that you had to be locked up here.","TWN":"你看起來並不是一個危險人物呀。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"내 말이-","JPN":"あんたもそう思う？","ENG":"Tell me about it.","TWN":"就是說嘛。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"신원미상의 테러리스트다! 절대로 허튼 짓 할 틈을 줘선 안 돼! 라면서 자기들끼리 유난 떨더라니까?","JPN":"身元不明のテロリストだ！　余計なことをする隙を与えるな！　とか散々騒いでおいてさ。","ENG":"\\"An unidentified terrorist! Don't let her try anything!\\" is what they said as they make a big deal about everything.","TWN":"他們見到我就說什麼“身分不明的恐怖分子！我們不能讓她逍遙法外！”"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"딱히 사람을 세뇌시키는 능력 같은 거 없다고 했는데 들은 척도 안 하더니 사람 코빼기 하나 안 비추는 시커먼 방에 날 가둬 놓은 거라고.","JPN":"人を洗脳する能力なんてないって言ってるのに聞く耳も持たないで、人気のない黒い部屋にあたしを閉じ込めたの。","ENG":"I told them I didn't have any brainwashing powers, but they didn't listen and just locked me up in a room with no human contact whatsoever.","TWN":"我跟他們解釋我根本就沒有洗腦能力，但他們根本不聽，硬是把我關進了漆黑一片的房間裡。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"확실히… 조금 지나친 처사긴 하군요.","JPN":"確かに……少し度の過ぎた待遇ではありますね。","ENG":"It certainly is... a bit harsh.","TWN":"這個處罰確實有些……過分了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"사람을 세뇌시키는 능력을 가졌단 이유만으로 사람을 이런 아무것도 없는 밀실에 가둬두다니.","JPN":"洗脳する能力があるという理由だけで、人をこんな何もない密室に閉じ込めるなんて。","ENG":"To lock someone up in an empty solitary cell just because they have brainwashing abilities.","TWN":"只是因為擁有洗腦能力，就把人家關進密室裡。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니, 그런 능력 없대도.","JPN":"いやだから、そんな能力持ってないってば。","ENG":"I just told you I don't have that ability.","TWN":"不，我說過沒那種能力。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그나저나 여긴 어떻게 들어온 거야? 지금 죄수들끼리 폭동이라도 난 상황인가?","JPN":"それより、どうやってここに入ってきたの？　囚人同士で暴動とか？","ENG":"Besides, how did you come in here? Are the prisoners rioting?","TWN":"話說你是怎麼進入這裡的？囚犯們集體造反了不成？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아니면 정말 네가 날 구해주러 온…","JPN":"それとも、本当にあんたがあたしを救いに……","ENG":"Or are you really here to save me–","TWN":"或者說你真的是來救我的白馬……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"왜 네가 여기 있지?","JPN":"なぜ貴様がここにいる？","ENG":"Why are you here?","TWN":"你怎麼在這裡？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…너!","JPN":"……あんた！","ENG":"...You!","TWN":"……你！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다짜고짜 공격이냐?","JPN":"会うなり攻撃を仕掛けてくるとは！","ENG":"Why don't you start with words, not attacks?","TWN":"不問青紅皂白就開始攻擊？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 어쩐지 얌전히 감옥에만 가둬둔다 했어.","JPN":"チッ、監獄に閉じ込められてるだけなんて、変だなと思ってたよ。","ENG":"Tsk, I knew it was too quiet and uneventful.","TWN":"嘖，怪不得一直把我關進監獄裡不聞不問。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"관리국에서 날 처리하라고 당신을 보낸 거지? 육익인 내가 살아있으면 거슬리니까.","JPN":"管理局であたしを処理するためにあんたを送ったんでしょ？　六翼のあたしが生きてるのが目障りだから。","ENG":"The Administration sent you to off me, didn't they? They don't want a Six Wings member like me alive.","TWN":"是管理局派你來殺我的吧？身為六翼的我一定是你們的眼中釘。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"육익…? 네가?","JPN":"六翼……？　貴様が？","ENG":"Six Wings...? You are?","TWN":"六翼……？你？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"여기까지 와 놓고 시치미 떼기는!","JPN":"ここまで来ておいて、しらばっくれるなよ！","ENG":"Drop the act! You've already made it this far!","TWN":"別裝蒜了！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…아무래도 말로 해선 안 될 모양이군.","JPN":"……どうやら話が通じる相手ではないようだ。","ENG":"...I guess I won't get through to you with words alone.","TWN":"……看來只能動手了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"경보 시스템은 네가 막아라, 가이드. 잠시 소란스러울 테니까.","JPN":"警報システムはお前が止めろ、ガイド。しばらくうるさくなるだろうから。","ENG":"Keep the alert system quiet, guide. It's going to be loud for a bit.","TWN":"這邊會有些騷亂，你去關閉警報系統吧。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"알겠습니다. 하지만 에이미 양을 너무 다치게 하진 마세요.","JPN":"わかりました。でも、あまりエイミーさんを傷つけないでくださいね。","ENG":"Will do. But please, don't hurt Amy too much.","TWN":"好吧，但請不要弄傷了艾米。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};